<template>
  <header class="fixed top-0 w-full z-50 bg-surface/80 dark:bg-surface/80 backdrop-blur-xl shadow-sm">
    <div class="flex justify-between items-center px-container-padding-mobile md:px-container-padding-desktop h-20 max-w-7xl mx-auto">
      <div class="flex items-center gap-4">
        <img
          alt="智伴 Logo"
          class="h-[60px] object-contain cursor-pointer"
          src="data:image/png;base64,"
          @click="scrollTo('hero')"
        />
        <span class="font-headline-md text-headline-md font-bold text-primary dark:text-primary-fixed hidden md:block">智伴</span>
      </div>
      <nav class="hidden md:flex gap-8">
        <a class="text-primary font-bold border-b-2 border-primary pb-1 hover:text-primary transition-colors duration-300 font-body-md text-body-md cursor-pointer" @click.prevent="scrollTo('hero')">Home</a>
        <a class="text-on-surface-variant font-medium hover:text-primary transition-colors duration-300 font-body-md text-body-md cursor-pointer" @click.prevent="scrollTo('dashboard')">Features</a>
        <a class="text-on-surface-variant font-medium hover:text-primary transition-colors duration-300 font-body-md text-body-md cursor-pointer" href="#">Care Network</a>
      </nav>
      <button
        class="bg-primary-container text-on-primary-container px-6 py-2 rounded-full font-label-md text-label-md hover:opacity-90 transition-opacity duration-300"
        @click="handleEnterConsole"
      >
        Enter Console
      </button>
    </div>
  </header>
</template>

<script setup>
import { useRouter } from 'vue-router'
import { useUserStore } from '../../stores/user.js'

const router = useRouter()
const userStore = useUserStore()

function handleEnterConsole() {
  if (userStore.isLoggedIn) {
    router.push(userStore.roleMap[userStore.role] || '/')
  } else {
    router.push('/login')
  }
}

function scrollTo(id) {
  document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' })
}
</script>
